import{_ as r,o,c as e,ag as d}from"./chunks/framework.BbyMWZAR.js";const P=JSON.parse('{"title":"GET vs POST：真正的区别与常见误解","description":"","frontmatter":{"title":"GET vs POST：真正的区别与常见误解","difficulty":"easy","tags":["HTTP","GET","POST","幂等"],"estimate":10},"headers":[],"relativePath":"domains/browser/qa/qa-13-get-vs-post.md","filePath":"domains/browser/qa/qa-13-get-vs-post.md","lastUpdated":1783504823000}'),l={name:"domains/browser/qa/qa-13-get-vs-post.md"};function a(s,t,i,n,T,g){return o(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="问答-13-入门-get-vs-post-真正的区别与常见误解" tabindex="-1">问答 13（入门）：GET vs POST：真正的区别与常见误解 <a class="header-anchor" href="#问答-13-入门-get-vs-post-真正的区别与常见误解" aria-label="Permalink to &quot;问答 13（入门）：GET vs POST：真正的区别与常见误解&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>GET 和 POST 有什么本质区别？「GET 参数放 URL 里，POST 放 body 里」这种说法准确吗？请从语义、幂等性、缓存、安全、body 支持、限制等多个维度回答。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>规范上的区别（语义）</strong></p><ul><li><strong>GET</strong>：请求资源，<strong>安全（safe）+ 幂等（idempotent）+ 可缓存</strong>。不应用于产生副作用。</li><li><strong>POST</strong>：提交数据、创建资源，<strong>不安全 + 不幂等 + 默认不缓存</strong>。</li></ul><p><strong>其它角度</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>GET</th><th>POST</th></tr></thead><tbody><tr><td>语义</td><td>读取</td><td>提交 / 副作用</td></tr><tr><td>幂等</td><td>是（重复请求结果相同）</td><td>否</td></tr><tr><td>可缓存</td><td>默认可缓存</td><td>默认不缓存（除非显式设 <code>Cache-Control</code>）</td></tr><tr><td>body</td><td>规范允许但<strong>不建议</strong>带 body，很多服务端 / 代理不会读</td><td>支持任意 body</td></tr><tr><td>URL 长度</td><td>受限于浏览器 / 服务器（约 2KB - 8KB）</td><td>无硬性限制（受服务端 body 限制）</td></tr><tr><td>参数位置</td><td>一般 query string</td><td>Body（<code>form-data</code>、<code>json</code> 等）</td></tr><tr><td>后退 / 刷新</td><td>无提示</td><td>浏览器提示「重新提交表单」</td></tr><tr><td>收藏 / 分享</td><td>天然分享（URL 完整）</td><td>不能</td></tr><tr><td>TLS 加密</td><td>二者都加密整个报文（含 URL 和 body）</td><td>同 GET</td></tr><tr><td>Referer</td><td>都会带</td><td>都会带</td></tr></tbody></table><p><strong>常见误解</strong></p><ol><li><strong>「GET 参数暴露，POST 更安全」——不准确。</strong><ul><li>二者在 HTTPS 上都加密。</li><li>GET 参数会被记录到浏览器历史、Referer、服务器 access log、CDN 日志里，敏感数据用 GET 更容易泄漏。</li><li>但 POST body 一样可能被网关记录，若身份校验依赖参数本身，二者安全都很脆弱。</li><li><strong>真正的安全靠 HTTPS + 认证 + 授权，不是靠 GET / POST</strong>。</li></ul></li><li><strong>「POST 传大数据能力强」——语义上没规定 body 大小，只是实践差异。</strong> URL 长度浏览器有限制，纯从容量看 POST 优。</li><li><strong>「GET 只能带参数不能带 body」——规范其实允许，但很多组件（代理、curl 版本、fetch 早期实现）会丢或忽略；实践中不建议。</strong></li></ol><p><strong>幂等性重要吗？</strong></p><ul><li>网络重试 / 客户端超时时会重发，幂等的 GET / PUT / DELETE 重发是安全的；POST 重发可能重复下单。</li><li>因此支付 / 创建接口通常配合<strong>幂等键（Idempotency-Key）</strong> 来避免重复。</li></ul><p><strong>方法列表</strong></p><ul><li><strong>安全</strong>：GET、HEAD、OPTIONS、TRACE。</li><li><strong>幂等</strong>：GET、HEAD、PUT、DELETE、OPTIONS、TRACE。</li><li><strong>不安全 + 不幂等</strong>：POST、PATCH。</li></ul><h2 id="追问-1-restful-api-里-put-和-post-分别用于什么-patch-呢" tabindex="-1">追问 1：RESTful API 里 PUT 和 POST 分别用于什么？PATCH 呢？ <a class="header-anchor" href="#追问-1-restful-api-里-put-和-post-分别用于什么-patch-呢" aria-label="Permalink to &quot;追问 1：RESTful API 里 PUT 和 POST 分别用于什么？PATCH 呢？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>POST /users</strong>：创建资源，服务端决定新 ID。不幂等。</li><li><strong>PUT /users/1</strong>：<strong>用请求 body 完全替换</strong>该资源。幂等（多次请求结果相同）。</li><li><strong>PATCH /users/1</strong>：部分更新（只改一部分字段）。语义上不要求幂等，但通常实现成幂等。</li><li>换句话说：POST 增，PUT 全量改，PATCH 增量改。</li><li>生产上很多 API 用 POST 兼做增改（不严格 REST），但接口文档应明确幂等性。</li></ul><h2 id="追问-2-get-请求会发送两次-tcp-包吗-是不是「一次请求头-一次请求体」" tabindex="-1">追问 2：GET 请求会发送两次 TCP 包吗？是不是「一次请求头，一次请求体」？ <a class="header-anchor" href="#追问-2-get-请求会发送两次-tcp-包吗-是不是「一次请求头-一次请求体」" aria-label="Permalink to &quot;追问 2：GET 请求会发送两次 TCP 包吗？是不是「一次请求头，一次请求体」？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>这是老面试题的误传。TCP 是流，浏览器一般会<strong>把请求头和 body 一起写入 TCP 缓冲区</strong>，是否分片由 MSS / Nagle 算法 / TCP 拥塞控制决定，跟 GET / POST 无关。</li><li>传闻可能来自 Firefox 曾经的实现：POST 会先发 header 等 100 Continue 再发 body（<code>Expect: 100-continue</code>），但这是特殊场景不是普遍现象，且现代浏览器基本不这么做。</li><li>结论：GET / POST 与 TCP 分片次数没有必然关系，别背这个错误结论。</li></ul><h2 id="追问-3-为什么表单默认-form-method-post-会有「重新提交」提示-而-get-没有" tabindex="-1">追问 3：为什么表单默认 <code>&lt;form method=&quot;post&quot;&gt;</code> 会有「重新提交」提示，而 GET 没有？ <a class="header-anchor" href="#追问-3-为什么表单默认-form-method-post-会有「重新提交」提示-而-get-没有" aria-label="Permalink to &quot;追问 3：为什么表单默认 `&lt;form method=&quot;post&quot;&gt;` 会有「重新提交」提示，而 GET 没有？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>因为 POST 语义是「产生副作用」，重复提交可能导致重复下单 / 重复扣款。浏览器在后退 / 刷新时会显示警告，让用户确认。</li><li>GET 是幂等 + 安全的，重复请求不应有副作用，浏览器直接重新发起，无警告。</li><li>前端最佳实践： <ul><li>提交后立即跳转（Post/Redirect/Get 模式，返回 303 See Other）。</li><li>按钮点击后置灰 / loading 防止重复点击。</li><li>服务端接入幂等键（<code>Idempotency-Key</code> header），即使重复提交也只处理一次。</li></ul></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110: HTTP Semantics</a>：GET/POST 方法与幂等性定义</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Methods" target="_blank" rel="noreferrer">MDN: HTTP request methods</a>：方法语义与常见误解</li><li><a href="https://www.rfc-editor.org/rfc/rfc9112.html" target="_blank" rel="noreferrer">RFC 9112: HTTP/1.1</a>：请求行与消息体格式</li></ul>',26)])])}const c=r(l,[["render",a]]);export{P as __pageData,c as default};
